143	static int _timespec_sub(struct timespec* a, struct timespec* b, struct timespec* result)
144	{
145	  if (a->tv_sec <  b->tv_sec) return -1;
146	  else if (a->tv_nsec <  b->tv_nsec) return -1;
147	
148	  result->tv_sec = a->tv_sec - b->tv_sec;
149	  result->tv_nsec = a->tv_nsec - b->tv_nsec;
150	
151	  if (result->tv_nsec < 0) {
152	    result->tv_sec--;
153	    result->tv_nsec += 1000000000;
154	  }
155	
156	  return 0;
157	}
